// export type EncodingType = typeof ENC_UTF8 | typeof ENC_BASE64;

export enum EncodingType {
  ENC_UTF8 = 'utf-8',
  ENC_BASE64 = 'base64',
}

export enum Branch {
  MASTER = 'master',
  PAGES = 'gh-pages',
}

export type fileType = {
  path: string;
  content: any;
  encoding: EncodingType;
};

export type ServeFiles = {
  token: string;
  message: string;
  repo: string | null;
  branch: Branch | null;
  owner: string | null;
};

type GitFileMode = '100644' | '100755' | '040000' | '160000' | '120000';
export interface GitFile {
  path: string;
  mode: GitFileMode;
  type: 'blob'; // specify the type, assuming it's always 'blob' for files
  sha?: string; // optional SHA for updating existing blobs
  content?: string; // optional content for creating a new blob
}

